#include <stdio.h>

#define MAX 50

struct Aluno {
    char nome[50];
    int matricula;
    float nota;
};

void main() {
    struct Aluno aluno1, aluno2;
    int choice, i;

    printf("Sistema de cadastro de alunos\n");
    printf("1-Cadastrar\n");
    printf("2-Listar\n");
    printf("3-Buscar por matricula\n");
    printf("0-Sair\n");
    printf("Digite a opção:\n");

    while (choice != 0) {
        scanf("%d", &choice);

        switch(choice) {
            case 1:
                aluno1.nome[0] = getchar();
                aluno1.matricula = 100;
                aluno1.nota = 0.0;
                printf("Nome: %s\n", aluno1.nome);
                break;

            case 2:
                printf("\nAlunos:\n");
                for(int i = 0; i < MAX; i++) {
                    printf("%d. %s\n", i, aluno1.nome[i]);
                }
                break;

            case 3:
                aluno2.nome[0] = getchar();
                aluno2.matricula = 100;
                aluno2.nota = 0.0;
                printf("Nome: %s\n", aluno2.nome);
                break;

            default:
                printf("Opção inválida!\n");
        }
    }
}
